// // Sign-extends the 11-bit input to 32 bits by replicating the least significant bit 21 times and shifting left by 2 bits
module top_module(inSh, out);input [10:0] inSh;

	 output reg [31:0] out;
	 reg [31:0] temp;

	always@(inSh)begin
		temp <= {{21{inSh[10]}}, inSh[10:0]};		
	end

	always@(temp)begin
		out <= temp << 2;
	end

endmodule
